/**
 * Notification log model — tracks sent notification history.
 *
 * Each NotificationLogEntry records a notification that was dispatched
 * through the notification system, capturing recipient, channel, type,
 * delivery status, and timestamps for auditing and querying.
 */

import type { NotificationChannel, NotificationStatus, NotificationType } from './notification.js';

export interface NotificationLogEntry {
  id: string;
  /** The notification ID from the original notification */
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  status: NotificationStatus;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
  createdAt: Date;
  sentAt: Date | null;
}

export interface NotificationLogQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: NotificationStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLogEntry data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLogEntry } from '../models/notification-log.js';
import type { NotificationChannel, NotificationStatus, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      status: record['status'] as NotificationStatus,
      subject: record['subject'] as string,
      body: record['body'] as string,
      metadata: JSON.parse(record['metadata'] as string) as Record<string, unknown>,
      createdAt: new Date(record['createdAt'] as string),
      sentAt: record['sentAt'] ? new Date(record['sentAt'] as string) : null,
    };
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      status: entity.status,
      subject: entity.subject,
      body: entity.body,
      metadata: JSON.stringify(entity.metadata),
      createdAt: entity.createdAt.toISOString(),
      sentAt: entity.sentAt ? entity.sentAt.toISOString() : '',
    };
  }

  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  findByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  findByType(type: NotificationType): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }

  findByStatus(status: NotificationStatus): NotificationLogEntry[] {
    return this.findAll((entry) => entry.status === status);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.findAll(
      (entry) => entry.createdAt >= startDate && entry.createdAt <= endDate,
    );
  }
}

/**
 * Notification history service — logs and queries sent notification history.
 *
 * Integrates with the NotificationService to automatically log every
 * dispatched notification. Provides query methods for retrieving
 * notification history by recipient, type, channel, status, and date range.
 */

import type { NotificationLogEntry, NotificationLogQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { Notification } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset ID counter (for testing). */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification that was dispatched by the notification service.
   */
  logNotification(notification: Notification, metadata: Record<string, unknown> = {}): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      status: notification.status,
      subject: notification.subject,
      body: notification.body,
      metadata,
      createdAt: notification.createdAt,
      sentAt: notification.sentAt,
    };

    this.repository.save(entry);
    this.logger.info(`Logged notification ${notification.id} (${notification.status}) to ${notification.recipient}`);
    return entry;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filters: NotificationLogQuery): NotificationLogEntry[] {
    return this.repository.findAll((entry) => {
      if (filters.recipient && entry.recipient !== filters.recipient) return false;
      if (filters.channel && entry.channel !== filters.channel) return false;
      if (filters.type && entry.type !== filters.type) return false;
      if (filters.status && entry.status !== filters.status) return false;
      if (filters.startDate && entry.createdAt < filters.startDate) return false;
      if (filters.endDate && entry.createdAt > filters.endDate) return false;
      return true;
    });
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries for a specific notification type.
   */
  getByType(type: NotificationLogQuery['type']!): NotificationLogEntry[] {
    return this.repository.findByType(type!);
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get a specific log entry by ID.
   */
  getById(id: string): NotificationLogEntry | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the total count of logged notifications.
   */
  count(): number {
    return this.repository.count();
  }
}

