import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed.',
    status: 'sent',
    createdAt: new Date('2026-01-15T10:00:00Z'),
    sentAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a notification and return the log entry', () => {
      const notification = makeNotification();
      const entry = historyService.logNotification(notification, { orderId: 'order-1' });

      expect(entry.id).toBe('log-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.subject).toBe('Order Confirmation: order-1');
      expect(entry.metadata).toEqual({ orderId: 'order-1' });
      expect(entry.sentAt).toEqual(new Date('2026-01-15T10:00:00Z'));
    });

    it('should generate sequential log IDs', () => {
      const n1 = makeNotification({ id: 'notif-0001' });
      const n2 = makeNotification({ id: 'notif-0002' });

      const entry1 = historyService.logNotification(n1);
      const entry2 = historyService.logNotification(n2);

      expect(entry1.id).toBe('log-0001');
      expect(entry2.id).toBe('log-0002');
    });

    it('should log failed notifications', () => {
      const notification = makeNotification({ status: 'failed', sentAt: null });
      const entry = historyService.logNotification(notification);

      expect(entry.status).toBe('failed');
      expect(entry.sentAt).toBeNull();
    });

    it('should default metadata to empty object', () => {
      const notification = makeNotification();
      const entry = historyService.logNotification(notification);

      expect(entry.metadata).toEqual({});
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.logNotification(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          channel: 'email',
          type: 'order_confirmation',
          status: 'sent',
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          channel: 'webhook',
          type: 'order_status_update',
          status: 'failed',
          createdAt: new Date('2026-01-16T10:00:00Z'),
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          channel: 'email',
          type: 'welcome',
          status: 'sent',
          createdAt: new Date('2026-01-17T10:00:00Z'),
        }),
      );
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'order_confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-17T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'welcome',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should return all entries with empty filters', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should return empty array when no matches', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.logNotification(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order_confirmation',
          createdAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'welcome',
          createdAt: new Date('2026-01-20T10:00:00Z'),
        }),
      );
    });

    it('getByRecipient should return entries for recipient', () => {
      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('getByType should return entries for type', () => {
      const results = historyService.getByType('welcome');
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('getByDateRange should return entries in range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-14T00:00:00Z'),
        new Date('2026-01-16T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0001');
    });

    it('getById should return specific entry', () => {
      const entry = historyService.getById('log-0001');
      expect(entry).toBeDefined();
      expect(entry?.notificationId).toBe('notif-0001');
    });

    it('getById should return undefined for missing entry', () => {
      expect(historyService.getById('log-9999')).toBeUndefined();
    });

    it('count should return total entries', () => {
      expect(historyService.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications when events are emitted', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.type).toBe('order_confirmation');
      expect(entries[0]?.status).toBe('sent');
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.metadata).toHaveProperty('orderId', 'order-1');
    });

    it('should log status change notifications', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const entries = historyService.query({ type: 'order_status_update' });
      expect(entries).toHaveLength(1);
      expect(entries[0]?.metadata).toHaveProperty('previousStatus', 'pending');
      expect(entries[0]?.metadata).toHaveProperty('newStatus', 'confirmed');
    });

    it('should log multiple notifications and query them', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(historyService.count()).toBe(2);

      const confirmations = historyService.getByType('order_confirmation');
      expect(confirmations).toHaveLength(1);

      const updates = historyService.getByType('order_status_update');
      expect(updates).toHaveLength(1);
    });
  });
});

