+/**
+ * Notification history service — logs and queries sent notification history.
+ *
+ * Integrates with the NotificationService to automatically log every
+ * dispatched notification. Provides query methods for retrieving
+ * notification history by recipient, type, channel, status, and date range.
+ */
+
+import type { NotificationLogEntry, NotificationLogQuery } from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type { Notification, NotificationType } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `log-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+/** Reset ID counter (for testing). */
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification that was dispatched by the notification service.
+   */
+  logNotification(notification: Notification, metadata: Record<string, unknown> = {}): NotificationLogEntry {
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: notification.id,
+      recipient: notification.recipient,
+      channel: notification.channel,
+      type: notification.type,
+      status: notification.status,
+      subject: notification.subject,
+      body: notification.body,
+      metadata,
+      createdAt: notification.createdAt,
+      sentAt: notification.sentAt,
+    };
+
+    this.repository.save(entry);
+    this.logger.info(`Logged notification ${notification.id} (${notification.status}) to ${notification.recipient}`);
+    return entry;
+  }
+
+  /**
+   * Query notification history with flexible filters.
+   */
+  query(filters: NotificationLogQuery): NotificationLogEntry[] {
+    return this.repository.findAll((entry) => {
+      if (filters.recipient && entry.recipient !== filters.recipient) return false;
+      if (filters.channel && entry.channel !== filters.channel) return false;
+      if (filters.type && entry.type !== filters.type) return false;
+      if (filters.status && entry.status !== filters.status) return false;
+      if (filters.startDate && entry.createdAt < filters.startDate) return false;
+      if (filters.endDate && entry.createdAt > filters.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Get all log entries for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLogEntry[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all log entries for a specific notification type.
+   */
+  getByType(type: NotificationType): NotificationLogEntry[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all log entries within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get a specific log entry by ID.
+   */
+  getById(id: string): NotificationLogEntry | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get the total count of logged notifications.
+   */
+  count(): number {
+    return this.repository.count();
+  }
+}

